class Solution:
    def winnerOfGame(self, colors: str) -> bool:
        n = len(colors)
        countA = countB = 0
        for i in range(1, n - 1):
            if colors[i-1] == colors[i] == colors[i+1]:
                if colors[i] == 'A':
                    countA += 1
                else:
                    countB += 1
        return countA > countB

